+    for (let r = 0; r < rows; r++) {
+      for (let c = 0; c < cols; c++) {
+        const idx = r * cols + c;
+        const val = Array.isArray(confidenceMap)
+          ? (Array.isArray(confidenceMap[r]) ? confidenceMap[r][c] : confidenceMap[idx])
+          : (confidenceMap[idx] || 0);
