+    this.group.add(this._phaseGroup);
+  }
+
+  _buildDopplerSpectrum() {
+    // Bar chart for Doppler frequency spectrum
+    const { dopplerBars, dopplerWidth, dopplerHeight } = this.config;
+    const barWidth = (dopplerWidth / dopplerBars) * 0.8;
